import { a11y, page, render } from "#test/browser"
import { extendConfig, UIProvider } from "../../providers/ui-provider"
import { Image } from "../image"
import { Picture, Source } from "./picture"

const src = "https://image.xyz/source"

describe("<Picture />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <Picture
        src={src}
        alt="img"
        sources={[
          { srcSet: src, media: "xl" },
          { srcSet: src, media: "lg" },
          { srcSet: src, media: "md" },
        ]}
      />,
    )
  })

  test("sets `displayName` correctly", () => {
    expect(Picture.name).toBe("Picture")
    expect(Source.name).toBe("Source")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <Picture src={src} alt="img" pictureProps={{ "data-testid": "picture" }}>
        <Source srcSet={src} data-testid="src" media="md" />
      </Picture>,
    )

    expect(page.getByTestId("picture").element().tagName).toBe("PICTURE")
    expect(page.getByTestId("src").element().tagName).toBe("SOURCE")
  })

  test("should render source elements", async () => {
    const { container } = await render(
      <Picture
        src={src}
        alt="img"
        sources={[
          { srcSet: src, media: "xl" },
          { srcSet: src, media: "lg" },
          { srcSet: src, media: "md" },
        ]}
      />,
    )
    const sources = container.querySelectorAll("source")
    expect(sources).toHaveLength(3)
  })

  test("should render custom source elements", async () => {
    const { container } = await render(
      <Picture>
        <Source srcSet={src} media="md" />
        <Source srcSet={src} media="lg" />
        <Source srcSet={src} media="xl" />
        <Image src={src} alt="img" />
      </Picture>,
    )
    const sources = container.querySelectorAll("source")
    expect(sources).toHaveLength(3)
    expect(sources[0]?.getAttribute("media")).toContain("(max-width: 768px)")
    expect(sources[1]?.getAttribute("media")).toContain("(max-width: 976px)")
    expect(sources[2]?.getAttribute("media")).toContain("(max-width: 1280px)")
  })

  test("should apply correct media queries from theme breakpoints", async () => {
    const { container } = await render(
      <Picture
        src={src}
        alt="img"
        sources={[
          { srcSet: src, media: "xl" },
          { srcSet: src, media: "lg" },
          { srcSet: src, media: "md" },
        ]}
      />,
    )
    const sources = container.querySelectorAll("source")
    expect(sources[0]?.getAttribute("media")).toContain("(max-width: 768px)")
    expect(sources[1]?.getAttribute("media")).toContain("(max-width: 976px)")
    expect(sources[2]?.getAttribute("media")).toContain("(max-width: 1280px)")
  })

  test("should apply correct media queries from maxW or minW", async () => {
    const { container } = await render(
      <Picture
        src={src}
        alt="img"
        sources={[
          { srcSet: src, maxW: "1280px" },
          { srcSet: src, maxW: 976, minW: 769 },
          { srcSet: src, maxW: "48rem" },
        ]}
      />,
    )
    const sources = container.querySelectorAll("source")
    expect(sources[0]?.getAttribute("media")).toContain("(max-width: 768px)")
    expect(sources[1]?.getAttribute("media")).toContain(
      "(min-width: 769px) and (max-width: 976px)",
    )
    expect(sources[2]?.getAttribute("media")).toContain("(max-width: 1280px)")
  })

  test("should sort sources", async () => {
    const { container } = await render(
      <Picture
        src={src}
        alt="img"
        sources={[
          { srcSet: src, media: "lg" },
          { srcSet: src, media: "(max-width: 768px)" },
          { srcSet: src, media: "xl" },
        ]}
      />,
    )
    const sources = container.querySelectorAll("source")
    expect(sources[0]?.getAttribute("media")).toContain("(max-width: 768px)")
    expect(sources[1]?.getAttribute("media")).toContain("(max-width: 976px)")
    expect(sources[2]?.getAttribute("media")).toContain("(max-width: 1280px)")
  })

  test("should not sort sources when enableSorting is false", async () => {
    const { container } = await render(
      <Picture
        src={src}
        alt="img"
        enableSorting={false}
        sources={[
          { srcSet: src, media: "md" },
          { srcSet: src, media: "(max-width: 976px)" },
          { srcSet: src, media: "xl" },
        ]}
      />,
    )
    const sources = container.querySelectorAll("source")
    expect(sources[0]?.getAttribute("media")).toContain("(max-width: 768px)")
    expect(sources[1]?.getAttribute("media")).toContain("(max-width: 976px)")
    expect(sources[2]?.getAttribute("media")).toContain("(max-width: 1280px)")
  })

  test("should sort sources with custom direction", async () => {
    const config = extendConfig({ breakpoint: { direction: "up" } })
    const { container } = await render(
      <Picture
        src={src}
        alt="img"
        sources={[
          { srcSet: src, media: "xl" },
          { srcSet: src, media: "lg" },
          { srcSet: src, media: "md" },
        ]}
      />,
      {
        wrapper: (props) => <UIProvider config={config} {...props} />,
      },
    )
    const sources = container.querySelectorAll("source")
    expect(sources[0]?.getAttribute("media")).toContain("(min-width: 1280px)")
    expect(sources[1]?.getAttribute("media")).toContain("(min-width: 976px)")
    expect(sources[2]?.getAttribute("media")).toContain("(min-width: 768px)")
  })
})

import type { FC } from "react"
import type { HTMLStyledProps, ThemeTokens, AnyString } from "@yamada-ui/react"
import type { ImageProps } from "../image"
import { useCallback, useMemo } from "react"
import { styled, tokenToValue, useSystem, getPx, isUndefined } from "@yamada-ui/react"
import { Image } from "../image"

const createQuery = (
  minW: number | string | undefined,
  maxW: number | string | undefined,
) => {
  let media = ""

  if (minW) {
    media = `(min-width: ${minW}px)`

    if (maxW) media += ` and (max-width: ${maxW}px)`
  } else {
    media = `(max-width: ${maxW}px)`
  }

  return media
}

export interface PictureSource extends SourceProps {
  /**
   * The maximum width for the source.
   *
   * If media is set, media takes precedence.
   */
  maxW?: AnyString | number | ThemeTokens["sizes"]
  /**
   * The minimum width for the source.
   *
   * If media is set, media takes precedence.
   */
  minW?: AnyString | number | ThemeTokens["sizes"]
  /**
   * The source set for the source element.
   */
  srcSet?: string
}

export interface PictureProps extends ImageProps {
  /**
   * If `true`, the sources will be sorted by the `minW` and `maxW` properties.
   *
   * @default true
   */
  enableSorting?: boolean
  /**
   * The sources for the picture element.
   */
  sources?: PictureSource[]
  /**
   * The props for the picture element.
   */
  pictureProps?: HTMLStyledProps<"picture">
}

/**
 * `Picture` is a component that uses the `picture` element to provide alternative images for different display or device scenarios.
 *
 * @see https://yamada-ui.com/docs/components/picture
 */
export const Picture: FC<PictureProps> = ({
  children,
  enableSorting = true,
  sources: sourcesProp = [],
  pictureProps,
  ...rest
}) => {
  const system = useSystem()
  const { queriesObj } = system.breakpoints
  const { direction = "down", identifier = "@media screen" } =
    system.config.breakpoint ?? {}
  const searchValue =
    identifier === "@media screen" ? "@media screen and " : `${identifier} `

  const compareSources = useCallback(
    (a: PictureSource, b: PictureSource) => {
      const k = direction === "down" ? "maxW" : "minW"

      if (isUndefined(a[k]) && !isUndefined(b[k])) return -1

      if (!isUndefined(a[k]) && isUndefined(b[k])) return 1

      return direction === "down"
        ? Number(a.maxW) - Number(b.maxW)
        : Number(b.minW) - Number(a.minW)
    },
    [direction],
  )

  const sources = useMemo(() => {
    const computedSources = sourcesProp.map(
      ({ maxW, media, minW, ...rest }) => {
        if (!media) {
          if (minW) minW = getPx(tokenToValue(system)("sizes", minW))
          if (maxW) maxW = getPx(tokenToValue(system)("sizes", maxW))

          media = createQuery(minW, maxW)

          return { ...rest, maxW, media, minW }
        } else {
          const { maxW, minW, query } = queriesObj[media] ?? {}

          if (query) media = query.replace(searchValue, "")

          return { ...rest, maxW, media, minW }
        }
      },
    )

    if (enableSorting) {
      return computedSources.sort(compareSources)
    } else {
      return computedSources
    }
  }, [
    sourcesProp,
    enableSorting,
    system,
    queriesObj,
    searchValue,
    compareSources,
  ])

  const sourceElements = useMemo(
    () =>
      sources.map(({ maxW: _maxW, minW: _minW, ...rest }, index) => (
        <styled.source key={index} {...rest} />
      )),
    [sources],
  )

  return (
    <styled.picture {...pictureProps}>
      {children ?? (
        <>
          {sourceElements}

          <Image {...rest} />
        </>
      )}
    </styled.picture>
  )
}

export interface SourceProps extends HTMLStyledProps<"source"> {
  /**
   * The media query for the source.
   */
  media?: AnyString | ThemeTokens["breakpoints"]
}

export const Source: FC<SourceProps> = ({ media, ...rest }) => {
  const { breakpoints, config } = useSystem()
  const { queriesObj } = breakpoints
  const { identifier = "@media screen" } = config.breakpoint ?? {}
  const searchValue =
    identifier === "@media screen" ? "@media screen and " : `${identifier} `

  const { query } = media ? (queriesObj[media] ?? {}) : {}

  if (query) media = query.replace(searchValue, "")

  return <styled.source media={media} {...rest} />
}
